"""
Auto-generated by build process.
Extracts templates and static files from embedded base64 data.
"""
import base64, gzip, os

FILES = {
    'static/app.js': '',
    'static/icons/icon-192.png': '',
    'static/icons/icon-512.png': '',
    'static/manifest.json': '',
    'static/styles.css': '',
    'templates/assistir.html': '',
    'templates/base.html': '',
    'templates/canais.html': '',
    'templates/charts.html': '',
    'templates/colecao.html': '',
    'templates/explorar.html': '',
    'templates/future_release.html': '',
    'templates/home.html': '',
    'templates/importar.html': '',
    'templates/login.html': '',
    'templates/pagination.html': '',
    'templates/secao.html': '',
    'templates/serie.html': '',
    'templates/tmdb_browse.html': '',
}

def extract_all():
    base = os.path.dirname(os.path.abspath(__file__))
    for relpath, encoded in FILES.items():
        dest = os.path.join(base, relpath)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        if not os.path.exists(dest):
            data = gzip.decompress(base64.b64decode(encoded))
            with open(dest, "wb") as f:
                f.write(data)
            print(f"[setup] Extracted: {relpath}")

if __name__ == "__main__":
    extract_all()
    print("[setup] All files extracted successfully.")
